// Input validation and output encoding
const escapeHtml = (str) => {
    return str.replace(/[&<>"']/g, (match) => {
        const escape = {
            '&': '&amp;',
            '<': '&lt;',
            '>': '&gt;',
            '"': '&quot;',
            "'": '&#39;'
        };
        return escape[match];
    });
};

// Use escapeHtml() before outputting user data
res.send(`<p>You entered: ${escapeHtml(userInput)}</p>`);

